package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withIgnoreHeaderCase();
        assertNotNull(result);
        assertTrue(result.getIgnoreHeaderCase());
        assertNotSame(original, result);

        // Also test that calling withIgnoreHeaderCase(true) returns equivalent result
        CSVFormat result2 = original.withIgnoreHeaderCase(true);
        assertEquals(result, result2);
    }
}
